function getPaymentMethod()
    {
        if ($this->paymentMethod) {
            return $this->paymentMethod;
        }
        if (!$this->paymentMethod) {
            if (array_key_exists('payment_method', $_POST)) {
                $this->paymentMethod = str_replace('woo-pagarme-payments-', '', sanitize_text_field($_POST['payment_method']));
                return $this->paymentMethod ;
            }
        }
        throw new \Exception(__('Empty payment method', 'woo-pagarme-payments'));
    }

/**
	 * Save the order of posts from sortable feature
	 *
	 * @return void
	 * @since 1.0
	 * @author Antonino Scarfi' <antonino.scarfi@yithemes.com>
	 */
function sort_posts() {
		global $wpdb;

		parse_str( $_REQUEST['order'], $data );

		if ( is_array( $data ) ) {
			//$this->init_menu_order( $_REQUEST['post_type'] );

			$id_arr = array( );
			foreach ( $data as $key => $values ) {
				foreach ( $values as $position => $id ) {
					$id_arr[] = $id;
				}
			}


			$menu_order_arr = array( );
			foreach ( $id_arr as $key => $id ) {
				$results = $wpdb->get_results( "SELECT menu_order FROM $wpdb->posts WHERE ID = " . $id );
				foreach ( $results as $result ) {
					$menu_order_arr[] = $result->menu_order;
				}
			}

			sort( $menu_order_arr );

			foreach ( $data as $key => $values ) {
				foreach ( $values as $position => $id ) {
					$wpdb->update( $wpdb->posts, array( 'menu_order' => $menu_order_arr[$position] ), array( 'ID' => $id ) );
				}
			}
		}

		die();
	}

